	case keys.KeyTab:
		m.nextFocusSlot()
		return m, nil
	case keys.KeySpace:
		if m.focusSlot == slotNav && m.nav.GetSelectedID() == ui.SidebarImportClickUp {
			m.state = stateClickUpSearch
